def is_valid_move(self, start, end):
    row_diff = abs(start[0] - end[0])
    col_diff = abs(start[1] - end[1])

    if self.current_player == 'B':
        direction = 1
    else:
        direction = -1

    if not (row_diff == 1 and col_diff in [1, 2]):
        return False

    start_piece = self.get_piece(*start)
    end_piece = self.get_piece(*end)

    if not isinstance(start_piece, Piece) or start_piece.color != self.current_player:
        return False

    if row_diff == 1 and end_piece != ' ':
        return False

    if row_diff == 2 and (end_piece == ' ' or end_piece.color == self.current_player):
        return False

    if row_diff == 2:
        jump_row = start[0] + direction
        jump_col = start[1] + (col_diff // 2)

        jump_piece = self.get_piece(jump_row, jump_col)
        if not isinstance(jump_piece, Piece) or jump_piece.color != self.current_player:
            return False

    return True
